def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    threshold = 0.75
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        decay = 1.0
        extra_penalties = 0.0
        complex_factor = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 8):
                penalty += (ratio ** (2 * k)) / (k ** 2 + 2)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j + 3))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 3
            priorities[i] = score * decay
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x)
                score += sign * (ratio ** x) / (x + 3)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 4))
            score = abs(score) * decay * 15
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 6)
                else:
                    temp += (ratio ** p) / (p * 5)
            multiplier = 30 if ratio < 2.5 else 20 if ratio < 2.8 else 12
            score = abs(temp) * multiplier
            if ratio > 2.9:
                extra = 0
                for m in range(1, 8):
                    extra += (ratio ** (m + 1)) / (m + 4)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp = 0
            for p in range(1, 20):
                cond = (p % 5 == 0, p % 4 == 0, p % 3 == 0)
                if cond[0]:
                    temp += (ratio ** p) / (p * 4)
                elif cond[1]:
                    temp -= (ratio ** p) / (p * 3)
                elif cond[2]:
                    temp += (ratio ** p) / (p * 6)
                else:
                    temp -= (ratio ** p) / (p * 5)
            multiplier = 40 if ratio < 1.3 else 28 if ratio < 1.7 else 18
            score = abs(temp) * multiplier
            if ratio > 1.8:
                extra = 0
                for m in range(1, 10):
                    extra += (ratio ** m) / (m + 2)
                score += extra * 4
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 25):
                mod_7 = p % 7
                if mod_7 == 0:
                    temp_score += (ratio ** p) / (p * 2)
                elif mod_7 == 1 or mod_7 == 4:
                    temp_score -= (ratio ** p) / (p * 5)
                elif mod_7 == 2 or mod_7 == 5:
                    temp_score += (ratio ** p) / (p * 4)
                else:
                    temp_score -= (ratio ** p) / (p * 6)
            if ratio < 0.15:
                multiplier = 45
            elif ratio < 0.3:
                multiplier = 35
            elif ratio < 0.5:
                multiplier = 22
            elif ratio < 0.7:
                multiplier = 12
            else:
                multiplier = 8
            score = abs(temp_score) * multiplier
            if ratio > 0.9:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n + 2)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for a in range(1, 4):
                nested_sum = 0.0
                for b in range(1, 4):
                    nested_sum += (a * b) / (bins[i] + b + 1)
                factor *= (1 + nested_sum / (a + 1))
            if i % 2 == 0:
                factor *= (1 + (item % (bins[i] + 1)) / (bins[i] + 2))
            else:
                factor *= (1 + ((item + i) % (bins[i] + 1)) / (bins[i] + 3))
            priorities[i] *= factor
            if ratio > threshold:
                smoothing = 0.0
                for s in range(1, 5):
                    smoothing += 1 / (s + ratio + bins[i])
                priorities[i] *= (1 + smoothing / 10)
    return priorities
